-- Ken's Hardened V2 Fix

local b64_0xlI1ll1 = {}
local char_0xIlIlll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIllIlI=1,#char_0xIlIlll do b64_0xlI1ll1[char_0xIlIlll:sub(i_0xIllIlI,i_0xIllIlI)] = i_0xIllIlI - 1 end

function b64_0xlI1ll1.dec_0xIlIl1I(d_0x11Illl)
    d_0x11Illl = string.gsub(d_0x11Illl, '[^'..char_0xIlIlll..'=]', '')
    local r_0xI11lll = {}
    for i_0xIllIlI=1, #d_0x11Illl, 4 do
        local c_0xI1IlIl = b64_0xlI1ll1[d_0x11Illl:sub(i_0xIllIlI,i_0xIllIlI)] or 0
        local c_0xIIIIlI = b64_0xlI1ll1[d_0x11Illl:sub(i_0xIllIlI+1,i_0xIllIlI+1)] or 0
        local c_0xllllII, c_0xlIIlll = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0x11Illl:sub(i_0xIllIlI+2,i_0xIllIlI+2)
        if ch3 == "=" then has3 = false else c_0xllllII = b64_0xlI1ll1[ch3] or 0 end
        local ch4 = d_0x11Illl:sub(i_0xIllIlI+3,i_0xIllIlI+3)
        if ch4 == "=" then has4 = false else c_0xlIIlll = b64_0xlI1ll1[ch4] or 0 end
        local b_0xll1l1I = c_0xI1IlIl * (2^18) + c_0xIIIIlI * (2^12) + c_0xllllII * (2^6) + c_0xlIIlll
        local b_0xIlIlII = math.floor(b_0xll1l1I / (2^16)) % (2^8)
        local b_0xllI1lI = math.floor(b_0xll1l1I / (2^8)) % (2^8)
        local b_0xlllllI = b_0xll1l1I % (2^8)
        table.insert(r_0xI11lll, string.char(b_0xIlIlII))
        if has3 then table.insert(r_0xI11lll, string.char(b_0xllI1lI)) end
        if has4 then table.insert(r_0xI11lll, string.char(b_0xlllllI)) end
    end
    return table.concat(r_0xI11lll)
end


local function bxor_0xIl1lII(a_0x1llIII,b_0xIllIII)
    if bit32 then return bit32.bxor(a_0x1llIII,b_0xIllIII) end
    local r_0xlIIllI = 0
    for i_0x1IlllI = 0, 7 do
        local x_0xIIIlIl = a_0x1llIII % 2
        local y_0xIIlIIl = b_0xIllIII % 2
        if x_0xIIIlIl ~= y_0xIIlIIl then r_0xlIIllI = r_0xlIIllI + (2^i_0x1IlllI) end
        a_0x1llIII = math.floor(a_0x1llIII / 2)
        b_0xIllIII = math.floor(b_0xIllIII / 2)
    end
    return r_0xlIIllI
end


local function bxor_str_0x1lllIl(s_0xllIIII, k_0x1Il1I1)
    local r_0xl1lllI = {}
    for i_0xIII1ll=1, #s_0xllIIII do
        local b_0xIIIIlI = string.byte(s_0xllIIII, i_0xIII1ll)
        local kb_0xIllIII = string.byte(k_0x1Il1I1, (i_0xIII1ll-1) % #k_0x1Il1I1 + 1)
        r_0xl1lllI[i_0xIII1ll] = string.char(bxor_0xIl1lII(b_0xIIIIlI, kb_0xIllIII))
    end
    return table.concat(r_0xl1lllI)
end


local function getkeys_0xIIlIII()
    local seed = b64_0xlI1ll1.dec_0xIlIl1I("elhRYWNvSUk=")
    local k1_enc = b64_0xlI1ll1.dec_0xIlIl1I("GBVkNTslHTM=")
    local k2_enc = b64_0xlI1ll1.dec_0xIlIl1I("O2AwDCIlH3A=")
    return bxor_str_0x1lllIl(k1_enc, seed), bxor_str_0x1lllIl(k2_enc, seed)
end


local function cff_0xll11I1(a_0xlIl1ll)
    local st_0xll1l1l = 0
    local res_0xll1I1I = a_0xlIl1ll
    while true do
        if st_0xll1l1l == 0 then
            res_0xll1I1I = res_0xll1I1I + 1
            st_0xll1l1l = 1
        elseif st_0xll1l1l == 1 then
            res_0xll1I1I = res_0xll1I1I * 2
            st_0xll1l1l = 2
        elseif st_0xll1l1l == 2 then
            res_0xll1I1I = res_0xll1I1I - 3
            st_0xll1l1l = 3
        else
            break
        end
    end
    return res_0xll1I1I
end


local function chain_0xIII1ll(x) return x*2 end
local function chain_0xIIllIl(x) return chain_0xIII1ll(x)+1 end


local d_0xl1II1I = {
  {op=255, val="", is_enc=true},
}
local pc_0xl1I1ll = 1
local stk_0xI1IIIl = {}
stk_0xI1IIIl._jmp = nil


local disp_0xIIlllI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIlIII()

local state_0xlIllII = 0
while true do
    if state_0xlIllII == 0 then  -- FETCH
        if pc_0xl1I1ll > #d_0xl1II1I then break end
        local inst = d_0xl1II1I[pc_0xl1I1ll]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xlI1ll1.dec_0xIlIl1I(val)
            d = bxor_str_0x1lllIl(d, k2)
            val = bxor_str_0x1lllIl(d, k1)
        end
        stk_0xI1IIIl._jmp = nil
        pc_0xl1I1ll = pc_0xl1I1ll + 1
        cur_op_0xIllII1 = opcode
        cur_val_0xII1lll = val
        state_0xlIllII = 1

    elseif state_0xlIllII == 1 then  -- EXECUTE
        local handler = disp_0xIIlllI[cur_op_0xIllII1]
        if handler then
            handler(stk_0xI1IIIl, cur_val_0xII1lll)
        end
        if stk_0xI1IIIl._jmp then
            pc_0xl1I1ll = pc_0xl1I1ll + stk_0xI1IIIl._jmp
        end
        state_0xlIllII = 0
    else
